  KeyType,
} from "./date_utils";

interface DayProps extends Pick<
  DateFilterOptionsWithDisabled,
  | "minDate"
  | "maxDate"
  | "excludeDates"
  | "excludeDateIntervals"
  | "includeDateIntervals"
  | "includeDates"
  | "filterDate"
  | "disabled"
> {
  ariaLabelPrefixWhenEnabled?: string;
  ariaLabelPrefixWhenDisabled?: string;
